TIER_DISCOUNT = {
    'bronze': 0.05,
    'silver': 0.10,
    'gold': 0.20
}

def apply_discount(price, tier):
    if tier not in TIER_DISCOUNT:
        raise ValueError(f'Unknown tier: {tier}')
    return price * (1 - TIER_DISCOUNT[tier])

